import React from 'react';

const entries = [
  {
    role: 'Freelance Web Developer',
    company: 'Self-employed',
    duration: '2024 – Present',
    description: 'Built and deployed personal and academic web projects using HTML, CSS, JavaScript, and React.',
  },
];

const Experience = () => (
  <section
    id="Experience"
    style={{ background: '#112240', fontFamily: "'Orbitron', sans-serif" }}
    className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
  >
    <h1 className="text-white text-4xl font-bold mb-12">Experience</h1>

    <div className="w-full max-w-2xl flex flex-col gap-5">
      {entries.map((e, i) => (
        <div
          key={i}
          style={{
            background: '#f8f9fa',
            borderLeft: '5px solid #0d6efd',
            borderRadius: '12px',
            padding: '20px',
          }}
        >
          <h3 style={{ color: '#0b1f3a', fontWeight: 'bold' }}>{e.role}</h3>
          <p>{e.company}</p>
          <p>{e.duration}</p>
          <p>{e.description}</p>
        </div>
      ))}
    </div>
  </section>
);

export default Experience;
